    def simplifyBuildingPCAClick(self):
        #Get buildings
        buildings = self.Canvas.getBuildings()
        
        #Create objects
        a = Algorithms()
        
        #Run simplification
        mbrs_res = []
        
        for building in buildings:
            mbr_res = a.simplifyBuildingPCA(building)
            mbrs_res.append(mbr_res)
        #Return results
        self.Canvas.setMBRs(mbrs_res)
        
        #Repaint
        self.Canvas.repaint()
        
