    def openShapefileClick(self):
        #Open file
        file_path, _ = QFileDialog.getOpenFileName(self.centralwidget, "Otevřít Shapefile", "", "Shapefiles (*.shp)")
        
        if file_path:            
            #Load data and finding global bounding box
            sf = shapefile.Reader(file_path)
            bbox = sf.bbox
            
            w_world = bbox[2] - bbox[0]
            h_world = bbox[3] - bbox[1]
            
            #Size of canvas
            canvas_w = self.Canvas.width()
            canvas_h = self.Canvas.height()
            
            #Calculate scale to fit the dataset into the canvas
            scale = min(canvas_w / w_world, canvas_h / h_world) * 0.9
            
            #Calculate center of the dataset
            cx_world = (bbox[0] + bbox[2]) / 2
            cy_world = (bbox[1] + bbox[3]) / 2
            
            buildings_list = []
            
            #Iteration over all shapes in the file
            for shape in sf.shapes():
                pol = QPolygonF()
                for x, y in shape.points:
                    #Transform world coordinates to screen coordinates
                    screen_x = (x - cx_world) * scale + (canvas_w / 2)
                    screen_y = -(y - cy_world) * scale + (canvas_h / 2) - 10
                    pol.append(QPointF(screen_x, screen_y))
                
                buildings_list.append(pol)
            
            #Set buildings to canvas
            self.Canvas.clearResult()
            self.Canvas.setBuildings(buildings_list)
            
    def clearResultsClick(self):
        #Clear results
        self.Canvas.clearResult()
    
